func (m *WebVitalMutation) FieldCleared(name string) bool {
	_, ok := m.clearedFields[name]
	return ok
}

// ClearField clears the value of the field with the given name. It returns an
// error if the field is not defined in the schema.
func (m *WebVitalMutation) ClearField(name string) error {
	return fmt.Errorf("unknown WebVital nullable field %s", name)
}

// ResetField resets all changes in the mutation for the field with the given name.
// It returns an error if the field is not defined in the schema.
func (m *WebVitalMutation) ResetField(name string) error {
	switch name {
	case webvital.FieldMetricName:
		m.ResetMetricName()
		return nil
	case webvital.FieldValue:
		m.ResetValue()
		return nil
	case webvital.FieldRating:
		m.ResetRating()
		return nil
	case webvital.FieldPath:
		m.ResetPath()
		return nil
	case webvital.FieldNavigationType:
		m.ResetNavigationType()
		return nil
	case webvital.FieldUserAgent:
		m.ResetUserAgent()
		return nil
	case webvital.FieldCreatedAt:
		m.ResetCreatedAt()
		return nil
	}
	return fmt.Errorf("unknown WebVital field %s", name)
}

